package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override to allow spying on super.read()
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testRead_returnsCharNotNewline() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) 'A').when(spyReader).superRead();

        int result = spyReader.read();

        assertEquals('A', result);
        assertEquals('A', getLastChar(spyReader));
        assertEquals(0, getLineCounter(spyReader));
    }

    @Test
    void testRead_returnsNewlineIncrementsLineCounter() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) '\n').when(spyReader).superRead();

        int result = spyReader.read();

        assertEquals('\n', result);
        assertEquals('\n', getLastChar(spyReader));
        assertEquals(1, getLineCounter(spyReader));
    }

    @Test
    void testRead_returnsEndOfStream() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(ExtendedBufferedReader.END_OF_STREAM).when(spyReader).superRead();

        int result = spyReader.read();

        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, getLastChar(spyReader));
        assertEquals(0, getLineCounter(spyReader));
    }

    // Helper method to access private lastChar field via reflection
    private int getLastChar(ExtendedBufferedReader reader) {
        try {
            var field = ExtendedBufferedReader.class.getDeclaredField("lastChar");
            field.setAccessible(true);
            return field.getInt(reader);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper method to access private lineCounter field via reflection
    private int getLineCounter(ExtendedBufferedReader reader) {
        try {
            var field = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
            field.setAccessible(true);
            return field.getInt(reader);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // To mock super.read() we add this method to ExtendedBufferedReader spy
    private static class ExtendedBufferedReader extends org.apache.commons.csv.ExtendedBufferedReader {
        ExtendedBufferedReader(Reader r) {
            super(r);
        }

        int superRead() throws IOException {
            return super.read();
        }
    }
}
